const apiKey = process.env.LINEAR_API_KEY;

// Try with proper bearer format
const searchRes = await fetch('https://api.linear.app/graphql', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
  body: JSON.stringify({ query: `{ issues(filter: { number: { eq: 19 } }) { nodes { id identifier title team { key } } } }` })
});
const searchData = await searchRes.json();
const nodes = searchData?.data?.issues?.nodes || [];
const issue = nodes.find(n => n.team?.key === 'CHA') || nodes[0];

if (!issue) {
  console.log("No issue found. Full response:", JSON.stringify(searchData));
  process.exit(0);
}

console.log(`Found issue: ${issue.identifier} - ${issue.title} (ID: ${issue.id})`);

// Now post the comment
const fs = await import('fs');
const reviewContent = fs.readFileSync('/Users/samjp/Code/stokowski-workspaces/CHA-19/plans/CHA-19-ceo-review.md', 'utf8');

const commentBody = `## Workpad\n\n**Status:** CEO Review complete — SCOPE EXPANSION recommended\n**Run:** 1 | **Date:** 2026-03-17\n\n---\n\n${reviewContent}`;

const commentRes = await fetch('https://api.linear.app/graphql', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
  body: JSON.stringify({
    query: `mutation($issueId: String!, $body: String!) { commentCreate(input: { issueId: $issueId, body: $body }) { success comment { id url } } }`,
    variables: { issueId: issue.id, body: commentBody }
  })
});
const commentData = await commentRes.json();
console.log("Comment result:", JSON.stringify(commentData, null, 2));

const apiKey = process.env.LINEAR_API_KEY;
// The key format is lin_api_... — Linear API keys don't need Bearer prefix for some endpoints
// Let's try both formats and also check if the key is valid

console.log("Key prefix:", apiKey?.substring(0, 10));
console.log("Key length:", apiKey?.length);

// Try with just the key directly (Linear's documented format)
for (const auth of [apiKey, `Bearer ${apiKey}`]) {
