   169→function applyMemory(mem) {
   170→	if (!mem) return;
   171→	var el = document.getElementById("memoryInfo");
   172→	if (!el) return;
   173→	var fmt = (b) => prettyBytes(b, { maximumFractionDigits: 0, space: false });
   174→	var localLlamaCpp = 0;
   175→	if (typeof mem.localLlamaCpp === "number") {
   176→		localLlamaCpp = mem.localLlamaCpp;
   177→	} else if (typeof mem.local_llama_cpp === "number") {
   178→		// Backward compatibility with older payload casing.
   179→		localLlamaCpp = mem.local_llama_cpp;
   180→	}
   181→	var localLlamaPart = localLlamaCpp > 0 ? ` (llama.cpp ${fmt(localLlamaCpp)})` : "";
   182→	el.textContent = `${fmt(mem.process)}${localLlamaPart} \u00b7 ${fmt(mem.available)} free / ${fmt(mem.total)}`;
   183→}
