   270→function updateAuthChrome(auth) {
   271→	var showLogout = !!(auth?.authenticated && !auth.auth_disabled && (auth.has_password || auth.has_passkeys));
   272→	if (logoutBtn) {
   273→		logoutBtn.style.display = showLogout ? "" : "none";
   274→	}
   275→	if (mobileMenuLogoutBtn) {
