   311→			if (!auth.authenticated) {
   312→				clearSensitiveData();
   313→				window.location.assign("/login");
   314→			}
   315→		})
   316→		.finally(() => {
   317→			window.dispatchEvent(new CustomEvent("moltis:auth-status-sync-complete"));
   318→		});
