   475→function fetchBootstrap() {
   476→	// Fetch bootstrap data asynchronously — populates sidebar, models, projects
   477→	// as soon as the data arrives, without blocking the initial page render.
   478→	fetch("/api/bootstrap?include_sessions=false")
   479→		.then((r) => {
