   481→				window.dispatchEvent(new CustomEvent("moltis:auth-status-changed"));
   482→				return Promise.reject(new Error("auth"));
   483→			}
   484→			return r.json();
   485→		})
   486→		.then((boot) => {
   487→			if (boot.channels) S.setCachedChannels(boot.channels.channels || boot.channels || []);
   488→			if (boot.sessions) {
   489→				var bootSessions = boot.sessions || [];
   490→				sessionStore.setAll(bootSessions);
   491→				// Dual-write to state.js for backward compat
   492→				S.setSessions(bootSessions);
